package com.google.gson;
import com.google.gson.internal.NonNullElementWrapperList;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonArrayTest {

  private JsonArray jsonArray;
  private JsonElement mockElement;

  @BeforeEach
  public void setUp() {
    jsonArray = new JsonArray();
    mockElement = mock(JsonElement.class);
  }

  @Test
  public void testGetAsDouble_withSingleElement_returnsElementDouble() {
    // Arrange
    when(mockElement.getAsDouble()).thenReturn(42.42);
    jsonArray.add(mockElement);

    // Act
    double result = jsonArray.getAsDouble();

    // Assert
    assertEquals(42.42, result);
    verify(mockElement).getAsDouble();
  }

  @Test
  public void testGetAsDouble_withEmptyArray_throwsException() throws Exception {
    // Arrange
    Method getAsSingleElement = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElement.setAccessible(true);

    // Act & Assert
    Exception exception = assertThrows(IllegalStateException.class, () -> {
      // invoke private method getAsSingleElement on empty array to confirm exception
      getAsSingleElement.invoke(jsonArray);
    });

    // The getAsDouble calls getAsSingleElement which will throw on empty array
    assertThrows(IllegalStateException.class, () -> jsonArray.getAsDouble());
  }

  @Test
  public void testPrivateGetAsSingleElement_returnsOnlyElement() throws NoSuchMethodException, IllegalAccessException, InvocationTargetException {
    // Arrange
    jsonArray.add(mockElement);
    Method getAsSingleElement = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElement.setAccessible(true);

    // Act
    JsonElement result = (JsonElement) getAsSingleElement.invoke(jsonArray);

    // Assert
    assertSame(mockElement, result);
  }

  @Test
  public void testPrivateGetAsSingleElement_withMultipleElements_throwsException() throws Exception {
    // Arrange
    jsonArray.add(mockElement);
    jsonArray.add(mockElement);
    Method getAsSingleElement = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElement.setAccessible(true);

    // Act & Assert
    InvocationTargetException thrown = assertThrows(InvocationTargetException.class, () -> {
      getAsSingleElement.invoke(jsonArray);
    });
    assertTrue(thrown.getCause() instanceof IllegalStateException);
  }
}
